};

bool isFloatNaN(uint32_t bits) {
    // For IEEE float: exponent all 1s (bits 23-30) and fraction non-zero (bits 0-22)
    uint32_t exponent = (bits >> 23) & 0xFF;
    uint32_t fraction = bits & 0x7FFFFF;
    return (exponent == 0xFF) && (fraction != 0);
}

