    std::cout << "~Bits.Zero = 0x" << std::hex << ~bits.Zero << std::endl;

    // With Bits.One (unknown bits = 0): exponent=0xFF, fraction=0 => Infinity, not NaN
    std::cout << "isNaN(Bits.One) = " << isFloatNaN(bits.One) << std::endl;

    // With ~Bits.Zero (unknown bits = 1): exponent=0xFF, fraction=0x7FFFFF => NaN
    std::cout << "isNaN(~Bits.Zero) = " << isFloatNaN(~bits.Zero) << std::endl;

    return 0;
}
