#include <iostream>
#include <cstdint>

bool isFloatNaN(uint32_t bits) {
    uint32_t exponent = (bits >> 23) & 0xFF;
    uint32_t fraction = bits & 0x7FFFFF;
    return (exponent == 0xFF) && (fraction != 0);
}

int main() {
    // Case 1: We know exponent bits are all 1s, fraction bits are unknown
    // Bits.One: exponent=0xFF, fraction=0 => NOT NaN (infinity)
    // ~Bits.Zero: exponent=0xFF, fraction=0x7FFFFF => NaN
    // So we can't prove anything about NaN-ness

    // Case 2: We know at least one fraction bit is 1, exponent bits unknown
    uint32_t known_one = 0x00000001;  // LSB is 1
    uint32_t known_zero = 0x00000000; // No bits known to be 0

    std::cout << "Case 2:" << std::endl;
    std::cout << "Bits.One = 0x" << std::hex << known_one 
              << " isNaN=" << isFloatNaN(known_one) << std::endl;
    std::cout << "~Bits.Zero = 0x" << std::hex << ~known_zero
              << " isNaN=" << isFloatNaN(~known_zero) << std::endl;

    // Case 3: We know exponent bits are NOT all 1s
    // Exponent bits 23-30: we know at least one is 0
    known_one = 0x00000000;
    known_zero = 0x7F800000;  // Exponent bits known to be 0

    std::cout << "\nCase 3:" << std::endl;
    std::cout << "Bits.One = 0x" << std::hex << known_one 
              << " isNaN=" << isFloatNaN(known_one) << std::endl;
    std::cout << "~Bits.Zero = 0x" << std::hex << ~known_zero
              << " isNaN=" << isFloatNaN(~known_zero) << std::endl;
    // ~Bits.Zero has exponent bits = 0x80 (not 0xFF), so NOT NaN
    // Therefore value can never be NaN!

    return 0;
}
EOF"}

